module RefModule (
    input wire clk,
    input wire reset,
    input wire [23:0] adc_input,
    output reg [23:0] adc_output
);
    reg [23:0] obf_internal_reg;

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            obf_internal_reg <= 24'b0;
        end else begin
            obf_internal_reg <= adc_input;
        end
    end

    always @(obf_internal_reg) begin
        adc_output <= obf_internal_reg;
    end
endmodule
